# state/evals.py — consistency evals for judgment agents (#192). Stdlib only.
# Measures run-to-run agreement of step-capability-tagger (per-step computed color) and
# opportunity-scorer (per-dimension / composite / B-B-P) and writes a confidence sidecar
# (evals/<target>.evals.json) + evals/_index.md. Pure metrics; the N runs are generated by
# the evaluating-consistency skill (Claude dispatches the agents — no API/CLI calls here).
from __future__ import annotations

import json
import sys
from itertools import combinations
from pathlib import Path

if __package__ in (None, ""):  # invoked as a script by absolute path
    sys.path.insert(0, str(Path(__file__).resolve().parent.parent))

from state.capability import compute_color, parse_step_capability

# Thresholds — module constants so they are testable and CLAUDE.md-overridable in spirit.
DIM_SPREAD_UNSTABLE = 2          # a dimension is unstable when max-min >= this
COMPOSITE_SPREAD_UNSTABLE = 0.5  # composite unstable when max-min > this
DEFAULT_N = 5


def _jaccard(a, b):
    a, b = set(a), set(b)
    if not a and not b:
        return 1.0
    return len(a & b) / len(a | b)


def _mean_pairwise_jaccard(sets):
    pairs = list(combinations(sets, 2))
    if not pairs:
        return 1.0
    return round(sum(_jaccard(a, b) for a, b in pairs) / len(pairs), 3)


def tagger_consistency(run_texts):
    """run_texts: PROC markdown per run, each carrying one **Step capability:** table.
    Returns per-step computed-color agreement + unstable flags (unstable = color not unanimous)."""
    runs = [r for r in (parse_step_capability(t) for t in run_texts) if r]
    steps = sorted({s for r in runs for s in r})
    out_steps = []
    for s in steps:
        attr_sets, colors = [], []
        for r in runs:
            if s not in r:
                continue
            attrs = r[s]["attributes"]
            attr_sets.append(attrs)
            try:
                colors.append(compute_color(attrs))
            except ValueError:
                colors.append("INVALID")
        unanimous = len(set(colors)) <= 1
        out_steps.append({
            "step": s,
            "colors": colors,
            "color_unanimous": unanimous,
            "jaccard_mean": _mean_pairwise_jaccard(attr_sets),
            "unstable": not unanimous,
        })
    return {
        "agent": "step-capability-tagger",
        "n_runs": len(runs),
        "unstable_step_count": sum(1 for st in out_steps if st["unstable"]),
        "steps": out_steps,
    }
